int sumMatrix(int (*a)[N],int n){
    if(n==1){
        return a[0][0];
    }
    int sum = 0;
    for(int i=0;i<n;i++){
        sum += a[i][0];
        sum += a[i][n-1];
    }
    for(int i=1;i<n-1;i++){
        sum += a[0][i];
        sum += a[n-1][i];
    }
    return sum;
}
